import torch
import torch.nn as nn
import timm

def get_model(num_classes=100, backbone='convnext_tiny'):
    if backbone == 'resnet50':
        model = torch.hub.load('pytorch/vision', 'resnet50', pretrained=True)
        model.fc = nn.Linear(model.fc.in_features, num_classes)
        return model
    elif backbone == 'convnext_tiny':
        model = timm.create_model('convnext_tiny.fb_in22k_ft_in1k', pretrained=True, num_classes=num_classes)
        return model
    elif backbone == 'vit_base_patch16_clip_224':
        model = timm.create_model('vit_base_patch16_clip_224.openai', pretrained=True, num_classes=num_classes)
        return model
    else:
        raise ValueError(f"Unknown backbone: {backbone}")
